async (params, browser) => {
  // Open Instagram DM inbox
  await browser.open('https://www.instagram.com/direct/inbox/')

  // Wait for DM inbox to load
  await browser.waitForSelector('div[class*=\'inbox\'], div[class*=\'direct\'], svg[aria-label=\'New message\'], main[role=\'main\']', 15000)

  // Let inbox fully initialize
  await browser.wait(2500)

  // Click new message button
  const open_new_message = await browser.evaluate(`const newMsgBtn = document.querySelector('svg[aria-label="New message"]')?.closest('button') || document.querySelector('svg[aria-label="New message"]')?.closest('div[role="button"]') || document.querySelector('div[role="button"] svg[aria-label="New message"]')?.closest('div[role="button"]'); if (newMsgBtn) { newMsgBtn.click(); } else { const allBtns = document.querySelectorAll('button, div[role="button"]'); for (const btn of allBtns) { if (btn.querySelector('svg[aria-label="New message"]') || btn.textContent.includes('New message')) { btn.click(); break; } } } return { clicked: true }`)

  // Wait for new message dialog
  await browser.wait(2000)

  // Wait for recipient search input
  await browser.waitForSelector('input[placeholder=\'Search...\'], input[name=\'queryBox\'], input[aria-label=\'Search\']', 10000)

  // Search for recipient
  const search_user = await browser.evaluate(`const searchInput = document.querySelector('input[placeholder="Search..."]') || document.querySelector('input[name="queryBox"]') || document.querySelector('input[aria-label="Search"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.value = ''; searchInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.username); searchInput.dispatchEvent(new Event('input', { bubbles: true })); searchInput.dispatchEvent(new Event('change', { bubbles: true })); } return { typed: !!searchInput }`)

  // Wait for user search results
  await browser.wait(2500)

  // Select recipient from results
  const select_user = await browser.evaluate(`const target = params.username.toLowerCase(); const results = document.querySelectorAll('div[role="dialog"] button, div[role="dialog"] div[role="button"], div[class*="result"] button, div[class*="result"] div[role="button"]'); let clicked = false; for (const item of results) { const text = item.textContent.trim().toLowerCase(); if (text.includes(target)) { item.click(); clicked = true; break; } } if (!clicked) { const allClickable = document.querySelectorAll('div[role="dialog"] div[class*="user"], div[role="listbox"] div[role="option"]'); for (const item of allClickable) { const text = item.textContent.trim().toLowerCase(); if (text.includes(target)) { item.click(); clicked = true; break; } } } if (!clicked) { const firstResult = document.querySelector('div[role="dialog"] div[role="button"]:not([aria-label])'); if (firstResult) { firstResult.click(); clicked = true; } } return { clicked: clicked, searched_for: params.username }`)

  // Wait for user selection
  await browser.wait(1500)

  // Click Next/Chat to open conversation
  const click_next = await browser.evaluate(`const nextBtn = Array.from(document.querySelectorAll('div[role="dialog"] button, div[role="dialog"] div[role="button"]')).find(b => b.textContent.trim().toLowerCase() === 'chat' || b.textContent.trim().toLowerCase() === 'next'); if (nextBtn) { nextBtn.click(); } return { clicked: !!nextBtn }`)

  // Wait for conversation to open
  await browser.wait(2500)

  // Wait for message input
  await browser.waitForSelector('textarea[placeholder=\'Message...\'], div[aria-label=\'Message\'], div[contenteditable=\'true\'][role=\'textbox\'], textarea[aria-label=\'Message\']', 10000)

  // Type message
  const type_message = await browser.evaluate(`const msgInput = document.querySelector('textarea[placeholder="Message..."]') || document.querySelector('div[aria-label="Message"]') || document.querySelector('div[contenteditable="true"][role="textbox"]') || document.querySelector('textarea[aria-label="Message"]'); if (!msgInput) return { success: false, message: 'Message input not found' }; msgInput.focus(); await new Promise(r => setTimeout(r, 300)); if (msgInput.tagName === 'TEXTAREA') { msgInput.value = ''; msgInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.message); msgInput.dispatchEvent(new Event('input', { bubbles: true })); } else { msgInput.textContent = ''; msgInput.dispatchEvent(new Event('input', { bubbles: true })); document.execCommand('insertText', false, params.message); msgInput.dispatchEvent(new Event('input', { bubbles: true })); } return { typed: true }`)

  // Wait before sending
  await browser.wait(800)

  // Send message
  const result = await browser.evaluate(`const sendBtn = document.querySelector('button[type="submit"]') || Array.from(document.querySelectorAll('div[role="button"], button')).find(b => b.textContent.trim().toLowerCase() === 'send'); if (sendBtn) { sendBtn.click(); return { success: true, message: 'Message sent', recipient: params.username }; } const msgInput = document.querySelector('textarea[placeholder="Message..."]') || document.querySelector('div[aria-label="Message"]') || document.querySelector('div[contenteditable="true"][role="textbox"]'); if (msgInput) { msgInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); return { success: true, message: 'Message sent via Enter key', recipient: params.username }; } return { success: false, message: 'Could not find send button or message input' }`)

  // Wait for message to be delivered
  await browser.wait(1500)

  return result
}
